INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 401, 2, 10046, 2, 0.0, "アヤネ", 0.0, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", "2030/12/17 14:59:59", 0.0, 102301, "2020/07/31 12:00:00", 24001);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 402, 1, 10046, 2, 0.0, "アヤネ", 2.21, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", "2030/12/17 14:59:59", 0.0, 102301, "2020/07/31 12:00:00", 24002);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 403, 2, 10046, 2, 0.0, "アヤネ", 0.0, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", "2030/12/17 14:59:59", 0.0, 102301, "2020/07/31 12:00:00", 24003);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 701, 2, 10046, 1, 0.0, "アサヒ", 1.99, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", "2030/12/17 14:59:59", 0.0, 192201, "2020/07/31 12:00:00", 24004);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 702, 1, 10046, 2, 0.0, "アサヒ", 2.21, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", "2030/12/17 14:59:59", 0.0, 192201, "2020/07/31 12:00:00", 24005);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 703, 2, 10046, 1, 0.0, "アサヒ", 3.33, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", "2030/12/17 14:59:59", 0.0, 192201, "2020/07/31 12:00:00", 24006);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 801, 2, 10046, 2, 0.0, "部員３", 0.0, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", "2030/12/17 14:59:59", 0.0, 192301, "2020/07/31 12:00:00", 24007);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 802, 1, 10046, 2, 0.0, "部員３", 2.68, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", "2030/12/17 14:59:59", 0.0, 192301, "2020/07/31 12:00:00", 24008);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 803, 2, 10046, 2, 0.0, "部員３", 0.0, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", "2030/12/17 14:59:59", 0.0, 192301, "2020/07/31 12:00:00", 24009);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 501, 1, 10046, 1, 0.0, "", 0.0, "やった！", "2030/12/17 14:59:59", 0.0, 192501, "2020/07/31 12:00:00", 24010);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 502, 1, 10046, 1, 0.0, "", 0.0, "勝ったよ！", "2030/12/17 14:59:59", 0.0, 192501, "2020/07/31 12:00:00", 24011);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 503, 1, 10046, 1, 0.0, "", 0.0, "いい調子！", "2030/12/17 14:59:59", 0.0, 192501, "2020/07/31 12:00:00", 24012);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 111, 6, 10046, 2, 0.0, "ミサト", 5.33, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", "2030/12/17 14:59:59", 0.0, 113501, "2020/07/31 12:00:00", 24013);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 112, 1, 10046, 2, 0.0, "ミサト", 6.85, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", "2030/12/17 14:59:59", 0.0, 113501, "2020/07/31 12:00:00", 24014);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 113, 1, 10046, 2, 0.0, "ミサト", 3.0, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", "2030/12/17 14:59:59", 0.0, 113501, "2020/07/31 12:00:00", 24015);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 611, 1, 10046, 2, 0.0, "ダイチ", 6.11, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", "2030/12/17 14:59:59", 0.0, 192401, "2020/07/31 12:00:00", 24016);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 612, 1, 10046, 2, 0.0, "ダイチ", 6.75, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", "2030/12/17 14:59:59", 0.0, 192401, "2020/07/31 12:00:00", 24017);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 613, 2, 10046, 2, 0.0, "ダイチ", 0.0, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", "2030/12/17 14:59:59", 0.0, 192401, "2020/07/31 12:00:00", 24018);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 211, 2, 10046, 1, 0.0, "ハツネ", 4.52, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", "2030/12/17 14:59:59", 0.0, 113401, "2020/07/31 12:00:00", 24019);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 212, 2, 10046, 1, 0.0, "ハツネ", 3.89, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", "2030/12/17 14:59:59", 0.0, 113401, "2020/07/31 12:00:00", 24020);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 213, 1, 10046, 2, 0.0, "ハツネ", 13.49, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", "2030/12/17 14:59:59", 0.0, 113401, "2020/07/31 12:00:00", 24021);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 311, 1, 10046, 2, 0.0, "カヤ", 3.17, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", "2030/12/17 14:59:59", 0.0, 106501, "2020/07/31 12:00:00", 24022);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 312, 1, 10046, 2, 0.0, "カヤ", 4.42, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", "2030/12/17 14:59:59", 0.0, 106501, "2020/07/31 12:00:00", 24023);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 313, 6, 10046, 1, 0.0, "カヤ", 2.89, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", "2030/12/17 14:59:59", 0.0, 106501, "2020/07/31 12:00:00", 24024);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 421, 4, 10046, 3, 0.0, "アヤネ", 3.71, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", "2030/12/17 14:59:59", 0.0, 102301, "2020/07/31 12:00:00", 24025);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 721, 2, 10046, 1, 0.0, "アサヒ", 5.1, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", "2030/12/17 14:59:59", 0.0, 192201, "2020/07/31 12:00:00", 24026);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 821, 1, 10046, 3, 0.0, "部員３", 4.34, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", "2030/12/17 14:59:59", 0.0, 192301, "2020/07/31 12:00:00", 24027);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 521, 1, 10046, 1, 0.0, "", 0.0, "いい勝負だったよ\nまたやろうね", "2030/12/17 14:59:59", 0.0, 192501, "2020/07/31 12:00:00", 24028);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 101, 1, 10046, 2, -360.0, "ミサト", 5.62, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", "2030/12/17 14:59:59", 0.0, 113501, "2020/07/31 12:00:00", 24029);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 102, 1, 10046, 2, -360.0, "ミサト", 9.58, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", "2030/12/17 14:59:59", 0.0, 113501, "2020/07/31 12:00:00", 24030);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 103, 2, 10046, 2, -360.0, "ミサト", 0.0, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", "2030/12/17 14:59:59", 0.0, 113501, "2020/07/31 12:00:00", 24031);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 104, 2, 10046, 1, -360.0, "ミサト", 9.13, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", "2030/12/17 14:59:59", 0.0, 113501, "2020/07/31 12:00:00", 24032);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 105, 1, 10046, 2, -360.0, "ミサト", 8.27, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", "2030/12/17 14:59:59", 0.0, 113501, "2020/07/31 12:00:00", 24033);
